class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def lca_in_bst(root: TreeNode, p: int, q: int) -> int:
    cur = root
    lo, hi = (p, q) if p < q else (q, p)
    while cur:
        if hi < cur.val:
            cur = cur.left
        elif lo > cur.val:
            cur = cur.right
        else:
            return cur.val
    return None

